const input = $input.first().json;

// Extract email metadata
const fromHeader = input.from || input.payload && input.payload.headers && input.payload.headers.find(function(h) { return h.name === 'From'; }) && input.payload.headers.find(function(h) { return h.name === 'From'; }).value || '';
const subject = input.subject || input.payload && input.payload.headers && input.payload.headers.find(function(h) { return h.name === 'Subject'; }) && input.payload.headers.find(function(h) { return h.name === 'Subject'; }).value || '';
const body = input.snippet || input.body || '';
const messageId = input.id || '';
const fromLower = fromHeader.toLowerCase();
const subjectLower = subject.toLowerCase();
const bodyLower = body.toLowerCase();

// Routing rules — order matters, first match wins
let route = 'GENERAL';
let agent = 'Aidan';
let priority = 'medium';
let reason = '';

// eMMA — Maryland state procurement
if (fromLower.indexOf('emma') !== -1 || fromLower.indexOf('emma.maryland') !== -1 || subjectLower.indexOf('solicitation') !== -1 || subjectLower.indexOf('bpm id') !== -1 || subjectLower.indexOf('rfx') !== -1) {
  route = 'NOVA';
  agent = 'Nova';
  priority = 'high';
  reason = 'eMMA procurement notification';
}
// SAM.gov — federal procurement
else if (fromLower.indexOf('sam.gov') !== -1 || fromLower.indexOf('beta.sam.gov') !== -1 || subjectLower.indexOf('sam.gov') !== -1 || subjectLower.indexOf('uei') !== -1 || subjectLower.indexOf('cage code') !== -1) {
  route = 'IRIS';
  agent = 'Iris';
  priority = 'critical';
  reason = 'SAM.gov registration update';
}
// IRS / Tax compliance
else if (fromLower.indexOf('irs.gov') !== -1 || fromLower.indexOf('treasury.gov') !== -1 || subjectLower.indexOf('form 1023') !== -1 || subjectLower.indexOf('990') !== -1 || subjectLower.indexOf('ein') !== -1) {
  route = 'IRIS';
  agent = 'Iris';
  priority = 'critical';
  reason = 'IRS / tax compliance';
}
// Maryland state agencies — grants
else if (fromLower.indexOf('maryland.gov') !== -1 || fromLower.indexOf('dllr') !== -1 || fromLower.indexOf('tedco') !== -1 || subjectLower.indexOf('grant') !== -1 || subjectLower.indexOf('award') !== -1 || subjectLower.indexOf('lighthouse') !== -1 || subjectLower.indexOf('earn') !== -1) {
  route = 'JORDAN';
  agent = 'Jordan';
  priority = 'high';
  reason = 'Maryland grant / state agency';
}
// Federal grants
else if (fromLower.indexOf('grants.gov') !== -1 || fromLower.indexOf('hrsa') !== -1 || fromLower.indexOf('sbir') !== -1 || subjectLower.indexOf('nofa') !== -1 || subjectLower.indexOf('notice of funding') !== -1) {
  route = 'JORDAN';
  agent = 'Jordan';
  priority = 'high';
  reason = 'Federal grant notification';
}
// FAA / Drone regulatory
else if (fromLower.indexOf('faa.gov') !== -1 || subjectLower.indexOf('part 107') !== -1 || subjectLower.indexOf('part 108') !== -1 || subjectLower.indexOf('laanc') !== -1 || subjectLower.indexOf('remote id') !== -1) {
  route = 'IRIS';
  agent = 'Iris';
  priority = 'critical';
  reason = 'FAA regulatory update';
}
// BD pipeline — known contacts
else if (fromLower.indexOf('mdot') !== -1 || fromLower.indexOf('sha.maryland') !== -1 || fromLower.indexOf('bge.com') !== -1 || fromLower.indexOf('medstar') !== -1 || fromLower.indexOf('umms') !== -1 || fromLower.indexOf('jhmi.edu') !== -1) {
  route = 'JORDAN';
  agent = 'Jordan';
  priority = 'critical';
  reason = 'BD pipeline contact';
}
// Techstars / ecosystem
else if (fromLower.indexOf('techstars') !== -1 || fromLower.indexOf('tedco') !== -1 || fromLower.indexOf('meia') !== -1 || subjectLower.indexOf('accelerator') !== -1 || subjectLower.indexOf('cohort') !== -1) {
  route = 'JORDAN';
  agent = 'Jordan';
  priority = 'high';
  reason = 'Ecosystem / accelerator';
}

return [{ json: {
  route: route,
  agent: agent,
  priority: priority,
  reason: reason,
  from: fromHeader,
  subject: subject,
  body: body.substring(0, 2000),
  messageId: messageId,
  timestamp: new Date().toISOString()
}}];

const http = require('http');
const input = $input.first().json;

// Fire Nova webhook with email content
const payload = JSON.stringify({
  rfp_name: input.subject || 'Email RFP',
  agency: input.from || 'Unknown',
  rfp_text: input.body || '',
  source: 'gmail_router',
  email_from: input.from,
  email_subject: input.subject
});

const opts = {
  hostname: 'host.docker.internal', port: 5678,
  path: '/webhook/nova-rfp', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
};

await new Promise(function(r) {
  const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); });
  req.on('error', r); req.write(payload); req.end();
});

return [{ json: { routed: true, to: 'Nova', from: input.from, subject: input.subject, reason: input.reason } }];

